import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@clerk/nextjs/server'
import User from '@/models/User'
import { validateAuth } from '@/lib/api-middleware'

export async function POST(req: NextRequest) {
  // Only allow admin to trigger migration
  // const authCheck = await validateAuth(req)
  // if (!authCheck || authCheck.user.role !== 'admin') {
  //   return NextResponse.json({ message: 'Unauthorized' }, { status: 401 })
  // }

  const clerk = createClient({ secretKey: process.env.CLERK_SECRET_KEY })

  try {
    const localUsers = await User.findAll()
    const results = []

    for (const localUser of localUsers) {
      try {
        // Create user in Clerk
        const clerkUser = await clerk.users.createUser({
          emailAddress: [localUser.email],
          firstName: localUser.fullName.split(' ')[0],
          lastName: localUser.fullName.split(' ').slice(1).join(' ') || '',
          password: 'TemporaryPassword123!', // Users should reset this
          publicMetadata: {
            role: localUser.role,
            sectorUnitId: localUser.sectorUnitId,
            legacyId: localUser.id
          },
        })
        
        results.push({ email: localUser.email, status: 'Migrated', clerkId: clerkUser.id })
      } catch (error: any) {
        results.push({ email: localUser.email, status: 'Failed', error: error.message })
      }
    }

    return NextResponse.json({ success: true, migrated: results })
  } catch (error: any) {
    return NextResponse.json({ success: false, message: error.message }, { status: 500 })
  }
}
